import{f as e,o as a,c as n,a2 as s}from"./chunks/framework.DHYrF-q6.js";const c=JSON.parse('{"title":"Code Review","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/code-review.md","filePath":"software-engineering/code-review.md","lastUpdated":1780925082000}'),r={name:"software-engineering/code-review.md"};function i(o,t,l,d,p,h){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="code-review" tabindex="-1">Code Review <a class="header-anchor" href="#code-review" aria-label="Permalink to &quot;Code Review&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>Review 最佳实践</td><td>什么应该被 Review、Review 流程、Review 粒度控制</td><td>极高</td></tr><tr><td>审查清单</td><td>功能性、可读性、安全性、性能、测试等审查维度</td><td>极高</td></tr><tr><td>文化建立</td><td>心理安全、对事不对人、Review 的标准与速度</td><td>高</td></tr><tr><td>工具辅助</td><td>静态分析、CI 集成、Review 自动化</td><td>中高</td></tr><tr><td>Review 角度</td><td>作者视角 vs 审查者视角、如何写出易于 Review 的 PR</td><td>中高</td></tr></tbody></table><hr><h2 id="一、code-review-的核心价值" tabindex="-1">一、Code Review 的核心价值 <a class="header-anchor" href="#一、code-review-的核心价值" aria-label="Permalink to &quot;一、Code Review 的核心价值&quot;">​</a></h2><p>Code Review 不只是&quot;找 bug&quot;。它的价值是多层次的：</p><table tabindex="0"><thead><tr><th>价值层次</th><th>说明</th></tr></thead><tbody><tr><td><strong>缺陷预防</strong></td><td>在代码合入前发现逻辑错误、边界条件遗漏</td></tr><tr><td><strong>知识传递</strong></td><td>让团队成员了解代码变更，消除&quot;单点知识&quot;风险</td></tr><tr><td><strong>代码一致性</strong></td><td>确保代码符合团队规范，风格统一</td></tr><tr><td><strong>设计改进</strong></td><td>审查中讨论架构和设计决策，提升整体设计质量</td></tr><tr><td><strong>团队成长</strong></td><td>新人通过阅读他人代码和审查反馈快速成长</td></tr><tr><td><strong>集体拥有感</strong></td><td>代码不再是&quot;某个人的代码&quot;，而是&quot;团队的代码&quot;</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">面试金句</p><p>&quot;Code Review 最重要的价值不是找 bug，而是<strong>知识传递和代码一致性</strong>。Bug 可以用测试找，但知识孤岛和风格分裂只能靠 Review 解决。&quot;</p></div><hr><h2 id="二、code-review-最佳实践" tabindex="-1">二、Code Review 最佳实践 <a class="header-anchor" href="#二、code-review-最佳实践" aria-label="Permalink to &quot;二、Code Review 最佳实践&quot;">​</a></h2><h3 id="_2-1-review-的粒度" tabindex="-1">2.1 Review 的粒度 <a class="header-anchor" href="#_2-1-review-的粒度" aria-label="Permalink to &quot;2.1 Review 的粒度&quot;">​</a></h3><blockquote><p><strong>一次 Review 的代码量不应超过 400 行。</strong></p></blockquote><p>研究表明，当 Review 代码量超过 400 行时，缺陷发现率急剧下降。人的注意力是有限的资源。</p><div class="danger custom-block"><p class="custom-block-title">现实问题</p><p>大厂面试常问：&quot;如果一个 PR 有 2000 行变更，你会怎么 Review？&quot;</p><ul><li>标准回复：请提交者拆分为多个逻辑独立的 commit / PR</li><li>如果无法拆分：分多次 Review，每次关注一个核心模块，做好笔记</li><li><strong>底线</strong>：不对超过 400 行的 PR 直接 Approve</li></ul></div><h3 id="_2-2-review-的节奏" tabindex="-1">2.2 Review 的节奏 <a class="header-anchor" href="#_2-2-review-的节奏" aria-label="Permalink to &quot;2.2 Review 的节奏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>建议值</th><th>原因</th></tr></thead><tbody><tr><td><strong>Review 响应时间</strong></td><td>&lt; 4 小时（工作时间）</td><td>避免上下文切换成本——提交者等太久会忘掉细节</td></tr><tr><td><strong>单次 Review 时长</strong></td><td>&lt; 60 分钟</td><td>超过 60 分钟注意力下降，Review 质量降低</td></tr><tr><td><strong>Review 频率</strong></td><td>每天 2-3 次固定时间</td><td>比&quot;随时 Review&quot;更高效，减少中断</td></tr></tbody></table><h3 id="_2-3-review-流程" tabindex="-1">2.3 Review 流程 <a class="header-anchor" href="#_2-3-review-流程" aria-label="Permalink to &quot;2.3 Review 流程&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提交者（Author）</span></span>
<span class="line"><span>  ├── 1. 自审查：运行测试、自查 CheckList、写好 PR 描述</span></span>
<span class="line"><span>  ├── 2. 提交 PR，@相关审查者</span></span>
<span class="line"><span>  └── 5. 处理反馈，回复每一条 comment（已修复 / 不修复 + 理由）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>审查者（Reviewer）</span></span>
<span class="line"><span>  ├── 3. 在 &lt; 4 小时内开始 Review</span></span>
<span class="line"><span>  ├── 4. 区分&quot;必须修改&quot;和&quot;建议优化&quot;（用标签区分）</span></span>
<span class="line"><span>  └── 6. 确认修改后 Approve</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="_2-4-提交者的责任-——-如何写出易于-review-的-pr" tabindex="-1">2.4 提交者的责任 —— 如何写出易于 Review 的 PR <a class="header-anchor" href="#_2-4-提交者的责任-——-如何写出易于-review-的-pr" aria-label="Permalink to &quot;2.4 提交者的责任 —— 如何写出易于 Review 的 PR&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ 好的 PR 描述模板：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 背景</span></span>
<span class="line"><span>为什么需要这个改动？（关联 Jira/TAPD 链接）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 改动内容</span></span>
<span class="line"><span>- 改动点 1：新增 XXX 功能</span></span>
<span class="line"><span>- 改动点 2：修复 YYY 边界条件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 测试</span></span>
<span class="line"><span>- [ ] 单元测试通过</span></span>
<span class="line"><span>- [ ] 集成测试通过</span></span>
<span class="line"><span>- [ ] 手工验证截图（如有 UI 变更）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 风险评估</span></span>
<span class="line"><span>- 影响范围：仅影响订单模块</span></span>
<span class="line"><span>- 回滚方案：可通过配置开关关闭</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><ul><li><strong>小步提交</strong>：一个 PR 只做一件事——功能、修复、重构分开提</li><li><strong>commit 信息清晰</strong>：让审查者能按 commit 顺序理解演进思路</li><li><strong>先自审查一遍</strong>：在提 PR 前自己过一遍 diff——能发现 30% 的问题</li></ul><hr><h2 id="三、code-review-审查清单" tabindex="-1">三、Code Review 审查清单 <a class="header-anchor" href="#三、code-review-审查清单" aria-label="Permalink to &quot;三、Code Review 审查清单&quot;">​</a></h2><h3 id="_3-1-功能性" tabindex="-1">3.1 功能性 <a class="header-anchor" href="#_3-1-功能性" aria-label="Permalink to &quot;3.1 功能性&quot;">​</a></h3><ul><li>[ ] 代码实现了需求描述的全部功能吗？</li><li>[ ] 是否处理了边界条件？（null、空集合、0、负数、超大值）</li><li>[ ] 是否考虑了并发场景？（多线程、分布式）</li><li>[ ] 错误处理是否完整？（异常不会被吞掉）</li></ul><h3 id="_3-2-可读性与可维护性" tabindex="-1">3.2 可读性与可维护性 <a class="header-anchor" href="#_3-2-可读性与可维护性" aria-label="Permalink to &quot;3.2 可读性与可维护性&quot;">​</a></h3><ul><li>[ ] 命名是否清晰、自解释？（不需要注释才能理解）</li><li>[ ] 函数是否足够短小？（&lt; 40 行，最好 &lt; 20 行）</li><li>[ ] 是否存在重复代码？（同一逻辑出现 2 次以上）</li><li>[ ] 圈复杂度是否过高？（&gt; 15 需要讨论是否重构）</li><li>[ ] 是否存在&quot;神奇数字&quot;？（应该定义为常量）</li></ul><h3 id="_3-3-设计" tabindex="-1">3.3 设计 <a class="header-anchor" href="#_3-3-设计" aria-label="Permalink to &quot;3.3 设计&quot;">​</a></h3><ul><li>[ ] 是否符合 SOLID 原则？尤其是单一职责和开闭原则</li><li>[ ] 类和模块的职责是否清晰？</li><li>[ ] 是否存在不必要的耦合？</li><li>[ ] 新增的抽象是否合理？（不过度设计，也不缺少必要抽象）</li></ul><h3 id="_3-4-安全" tabindex="-1">3.4 安全 <a class="header-anchor" href="#_3-4-安全" aria-label="Permalink to &quot;3.4 安全&quot;">​</a></h3><ul><li>[ ] 是否有 SQL 注入风险？（是否使用了参数化查询）</li><li>[ ] 用户输入是否经过校验和过滤？</li><li>[ ] 敏感信息（密码、Token）是否可能被日志输出？</li><li>[ ] 权限校验是否完整？</li></ul><h3 id="_3-5-性能" tabindex="-1">3.5 性能 <a class="header-anchor" href="#_3-5-性能" aria-label="Permalink to &quot;3.5 性能&quot;">​</a></h3><ul><li>[ ] 是否存在不必要的数据库查询？（N+1 问题）</li><li>[ ] 循环内是否有耗时操作？（数据库调用、远程 RPC）</li><li>[ ] 大对象是否及时释放？</li><li>[ ] 是否有潜在的内存泄漏？</li></ul><h3 id="_3-6-测试" tabindex="-1">3.6 测试 <a class="header-anchor" href="#_3-6-测试" aria-label="Permalink to &quot;3.6 测试&quot;">​</a></h3><ul><li>[ ] 是否有足够的单元测试？（核心逻辑覆盖率 &gt; 80%）</li><li>[ ] 测试是否覆盖了主要分支和边界条件？</li><li>[ ] 测试是否独立？（不依赖执行顺序）</li><li>[ ] Mock 使用是否合理？</li></ul><hr><h2 id="四、code-review-文化建立" tabindex="-1">四、Code Review 文化建立 <a class="header-anchor" href="#四、code-review-文化建立" aria-label="Permalink to &quot;四、Code Review 文化建立&quot;">​</a></h2><h3 id="_4-1-心理安全" tabindex="-1">4.1 心理安全 <a class="header-anchor" href="#_4-1-心理安全" aria-label="Permalink to &quot;4.1 心理安全&quot;">​</a></h3><p>Code Review 是技术活动，但本质上是<strong>人与人的沟通</strong>。心理安全是有效 Review 的前提。</p><table tabindex="0"><thead><tr><th>原则</th><th>反例</th><th>正例</th></tr></thead><tbody><tr><td><strong>对事不对人</strong></td><td>&quot;你这样写太蠢了&quot;</td><td>&quot;这个循环内调用 RPC 有性能风险，建议先批量查出来&quot;</td></tr><tr><td><strong>提问而非命令</strong></td><td>&quot;这里必须改成 X&quot;</td><td>&quot;这里如果用 X 方案会不会更好处理并发？你有什么考虑？&quot;</td></tr><tr><td><strong>认可好的部分</strong></td><td>只提问题不提优点</td><td>&quot;这个错误处理写得很清晰 👍 有个小建议...&quot;</td></tr><tr><td><strong>接受被反驳</strong></td><td>&quot;我是 Senior，听我的&quot;</td><td>&quot;理解你的思路了，那我们保留你的方案，加个注释说明&quot;</td></tr></tbody></table><h3 id="_4-2-review-意见分级" tabindex="-1">4.2 Review 意见分级 <a class="header-anchor" href="#_4-2-review-意见分级" aria-label="Permalink to &quot;4.2 Review 意见分级&quot;">​</a></h3><p>使用标签区分意见的严重程度：</p><table tabindex="0"><thead><tr><th>标签</th><th>含义</th><th>处理</th></tr></thead><tbody><tr><td><strong>blocker</strong></td><td>必须修改才能合入（有 bug、安全漏洞）</td><td>必须修，不修不 Approve</td></tr><tr><td><strong>suggestion</strong></td><td>建议修改，但当前写法也能接受</td><td>提交者自行判断是否采纳</td></tr><tr><td><strong>question</strong></td><td>提出问题，寻求解释或讨论</td><td>回答即可，不需要修改代码</td></tr><tr><td><strong>praise</strong></td><td>值得肯定的地方</td><td>——</td></tr></tbody></table><h3 id="_4-3-建立-review-文化的关键实践" tabindex="-1">4.3 建立 Review 文化的关键实践 <a class="header-anchor" href="#_4-3-建立-review-文化的关键实践" aria-label="Permalink to &quot;4.3 建立 Review 文化的关键实践&quot;">​</a></h3><ol><li><strong>从 Lead 开始</strong>：技术 Leader 先接受 Review 并开放讨论，以身作则</li><li><strong>Review 速度优先于 Review 深度</strong>：快速回复（即便只是&quot;Looks good, will review in detail later&quot;）比深度 Review 更能建立信任</li><li><strong>新人友好</strong>：对新人代码的 Review 侧重教学而非批评，多用 question 而非 blocker</li><li><strong>数据驱动</strong>：统计 Review 数据（Review 覆盖率、平均响应时间、缺陷拦截率），用数据说服团队</li></ol><div class="tip custom-block"><p class="custom-block-title">文化建立的核心</p><p>Code Review 文化的核心不是&quot;找出别人的错误&quot;，而是**&quot;我们一起让代码变得更好&quot;**。审查者和提交者是一边的，对立面是&quot;潜在的 bug 和技术债务&quot;。</p></div><hr><h2 id="五、工具辅助" tabindex="-1">五、工具辅助 <a class="header-anchor" href="#五、工具辅助" aria-label="Permalink to &quot;五、工具辅助&quot;">​</a></h2><h3 id="_5-1-自动化检查-ci-流水线集成" tabindex="-1">5.1 自动化检查（CI 流水线集成） <a class="header-anchor" href="#_5-1-自动化检查-ci-流水线集成" aria-label="Permalink to &quot;5.1 自动化检查（CI 流水线集成）&quot;">​</a></h3><p>人工 Review 应该聚焦在设计、逻辑、可读性等机器无法判断的维度。以下内容应该在 CI 阶段自动检查：</p><table tabindex="0"><thead><tr><th>检查项</th><th>工具（Java 生态）</th><th>建议配置</th></tr></thead><tbody><tr><td>代码风格</td><td>Checkstyle / SpotBugs</td><td>团队统一配置，禁止个人修改</td></tr><tr><td>静态分析</td><td>SonarQube</td><td>质量门禁：新增代码无 Blocker/Critical</td></tr><tr><td>圈复杂度</td><td>SonarQube / PMD</td><td>方法级别 &gt; 15 报警，&gt; 20 拦截</td></tr><tr><td>测试覆盖率</td><td>JaCoCo + SonarQube</td><td>增量代码覆盖率 &gt; 80%</td></tr><tr><td>安全扫描</td><td>OWASP Dependency-Check</td><td>有高危漏洞时自动拦截</td></tr></tbody></table><h3 id="_5-2-review-平台" tabindex="-1">5.2 Review 平台 <a class="header-anchor" href="#_5-2-review-平台" aria-label="Permalink to &quot;5.2 Review 平台&quot;">​</a></h3><table tabindex="0"><thead><tr><th>平台</th><th>特点</th></tr></thead><tbody><tr><td><strong>GitHub Pull Request</strong></td><td>最普及，Review 功能完善，支持 Suggested Changes</td></tr><tr><td><strong>GitLab Merge Request</strong></td><td>与 CI 紧密集成，支持 Approval Rules</td></tr><tr><td><strong>Gerrit</strong></td><td>严格的逐 commit Review，适合大型项目</td></tr><tr><td><strong>Crucible</strong></td><td>Atlassian 生态，与 Jira 深度集成</td></tr></tbody></table><hr><h2 id="⭐-面试高频问题" tabindex="-1">⭐ 面试高频问题 <a class="header-anchor" href="#⭐-面试高频问题" aria-label="Permalink to &quot;⭐ 面试高频问题&quot;">​</a></h2><h3 id="q1-你认为好的-code-review-是什么样的" tabindex="-1">Q1：你认为好的 Code Review 是什么样的？ <a class="header-anchor" href="#q1-你认为好的-code-review-是什么样的" aria-label="Permalink to &quot;Q1：你认为好的 Code Review 是什么样的？&quot;">​</a></h3><p><strong>标准答案</strong>：好的 Code Review 具有四个特征：</p><ol><li><strong>及时</strong>：提交 PR 后 4 小时内得到回复</li><li><strong>聚焦</strong>：每次 Review 不超过 400 行，审查者能深度理解</li><li><strong>有建设性</strong>：feedback 区分 blocker（必须改）和 suggestion（建议改），对事不对人，既有批评也有认可</li><li><strong>有来有回</strong>：审查者提问，提交者回答，形成技术讨论而非单向命令</li></ol><p><strong>一句话总结</strong>：&quot;好的 Code Review 让提交者愿意再提 PR，不好的 Code Review 让提交者尽量避免提 PR。&quot;</p><h3 id="q2-code-review-时你最关注哪些方面-优先级如何排序" tabindex="-1">Q2：Code Review 时你最关注哪些方面？优先级如何排序？ <a class="header-anchor" href="#q2-code-review-时你最关注哪些方面-优先级如何排序" aria-label="Permalink to &quot;Q2：Code Review 时你最关注哪些方面？优先级如何排序？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ol><li><strong>正确性</strong>（最高优先级）：逻辑是否对？边界条件是否处理？是否存在并发问题？</li><li><strong>安全性</strong>：是否有注入风险？敏感信息是否泄露？权限是否正确？</li><li><strong>设计</strong>：是否符合设计原则？职责是否清晰？是否存在不必要的耦合？</li><li><strong>可读性</strong>：命名是否清晰？方法是否过长？是否存在魔法数字？</li><li><strong>性能</strong>：是否有明显的性能问题（N+1、循环内 RPC）？</li><li><strong>测试</strong>：核心逻辑是否有测试覆盖？</li></ol><p><strong>优先顺序的逻辑</strong>：Bug &gt; 安全 &gt; 设计 &gt; 可读性 &gt; 性能 &gt; 测试。Bug 和安全是底线，设计和可读性是长期价值，性能和测试是锦上添花。</p><h3 id="q3-如何处理-code-review-中的分歧" tabindex="-1">Q3：如何处理 Code Review 中的分歧？ <a class="header-anchor" href="#q3-如何处理-code-review-中的分歧" aria-label="Permalink to &quot;Q3：如何处理 Code Review 中的分歧？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ol><li><strong>先听对方解释</strong>：对方的方案可能有你不知道的上下文约束</li><li><strong>用数据而非权威</strong>：不是说&quot;我是 Senior 所以听我的&quot;，而是&quot;这个方案在 XX 场景下有 3 倍性能差距，这是 benchmark 结果&quot;</li><li><strong>对齐原则</strong>：回到团队的设计原则和编码规范——原则不一致的先对齐原则</li><li><strong>升级决策</strong>：如果 15 分钟内无法达成一致，拉第三方（Tech Lead / 架构师）参与决策</li><li><strong>记录决策</strong>：无论结果如何，把决策和理由写在 PR 评论中，方便未来回溯</li></ol><h3 id="q4-你们团队的-code-review-流程是怎样的-有什么经验教训" tabindex="-1">Q4：你们团队的 Code Review 流程是怎样的？有什么经验教训？ <a class="header-anchor" href="#q4-你们团队的-code-review-流程是怎样的-有什么经验教训" aria-label="Permalink to &quot;Q4：你们团队的 Code Review 流程是怎样的？有什么经验教训？&quot;">​</a></h3><p><strong>标准答案</strong>（候选回答框架）：</p><p>流程：提交者自审 → 提 PR（写好描述 + 关联 Issue）→ 指定 1-2 位审查者 → 审查者在 4 小时内 Review → 提交者处理反馈 → 审查者确认 → Approve + Merge。</p><p>经验教训：</p><ol><li><strong>PR 越小越好</strong>：曾经有 PR 2000+ 行，Review 了 3 天，效率极低。后来规定 &gt; 600 行必须拆分</li><li><strong>自动化先行</strong>：曾经 30% 的 Review 评论是格式问题，接入 Checkstyle + CI 后这类评论降为零</li><li><strong>新人教育</strong>：新人前三个 PR 安排 Senior 做&quot;教学式 Review&quot;，每个 blocker 附带解释和正例代码</li></ol><h3 id="q5-如何看待-code-review-拖慢交付速度-的观点" tabindex="-1">Q5：如何看待&quot;Code Review 拖慢交付速度&quot;的观点？ <a class="header-anchor" href="#q5-如何看待-code-review-拖慢交付速度-的观点" aria-label="Permalink to &quot;Q5：如何看待&quot;Code Review 拖慢交付速度&quot;的观点？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ul><li><strong>短期确实会慢</strong>：Review + 修改反馈需要额外时间（通常 +20%-50% 的代码合入时间）</li><li><strong>长期反而更快</strong>：Review 减少 bug 返工（修一个线上 bug 的成本是 Review 的 10 倍以上），Review 让团队成员都了解代码（减少&quot;只有一个人懂&quot;导致阻塞的情况）</li><li><strong>关键在于优化流程</strong>：如果 Review 太慢，问题不在 Review 本身，而在流程——PR 太大、审查者太少、Review 时间不固定</li></ul><div class="danger custom-block"><p class="custom-block-title">必须强调</p><p>Code Review 不是可选项——Google、Microsoft 的研究都表明，Code Review 是<strong>发现 bug 最有效的手段</strong>，比测试更有效。减少 Review 来提速，等于透支未来来支付现在。</p></div><h3 id="q6-如何处理遗留代码没有测试、无法安全重构的情况" tabindex="-1">Q6：如何处理遗留代码没有测试、无法安全重构的情况？ <a class="header-anchor" href="#q6-如何处理遗留代码没有测试、无法安全重构的情况" aria-label="Permalink to &quot;Q6：如何处理遗留代码没有测试、无法安全重构的情况？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><ol><li><strong>先加特征测试（Characterization Test）</strong>：不测试&quot;正确的行为&quot;，只测试&quot;当前的行为&quot;——给现有代码拍一张快照</li><li><strong>从最外层开始</strong>：先写集成测试（对接口级别），再逐步深入</li><li><strong>识别接缝（Seam）</strong>：找到可以安全修改的点——一个类、一个方法、甚至一个 if 分支</li><li><strong>绞杀者模式</strong>：新建模块替代旧模块，而不是在旧代码上修修补补</li><li><strong>每次只改一点点</strong>：每次重构后运行特征测试确保行为不变</li></ol><p><strong>面试金句</strong>：&quot;重构的黄金法则——在没有测试的情况下，你是考古学家不是外科医生。你要小心翼翼地挖掘、记录，而不是大刀阔斧地切割。&quot;</p><h3 id="q7-如何衡量-code-review-的效果" tabindex="-1">Q7：如何衡量 Code Review 的效果？ <a class="header-anchor" href="#q7-如何衡量-code-review-的效果" aria-label="Permalink to &quot;Q7：如何衡量 Code Review 的效果？&quot;">​</a></h3><p><strong>标准答案</strong>：</p><table tabindex="0"><thead><tr><th>指标</th><th>衡量方式</th></tr></thead><tbody><tr><td><strong>缺陷拦截率</strong></td><td>Review 发现的问题数 / (Review 发现 + 上线后发现)</td></tr><tr><td><strong>Review 覆盖率</strong></td><td>被 Review 的 PR 数 / 总 PR 数</td></tr><tr><td><strong>Review 响应时间</strong></td><td>PR 提交到首次 Review 的时间中位数</td></tr><tr><td><strong>代码质量趋势</strong></td><td>SonarQube 的代码质量评分变化</td></tr><tr><td><strong>知识分布</strong></td><td>每个模块有多少人 Review 过相关 PR</td></tr></tbody></table><p>核心指标是<strong>缺陷拦截率</strong>——目标是 &gt; 60%。如果 Review 拦截率持续很低（&lt; 20%），可能说明 Review 流于形式，需要改进流程或培训。</p>`,83)])])}const g=e(r,[["render",i]]);export{c as __pageData,g as default};
